def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, _, val = line.partition(":")
        key = key.strip().lower()
        val = val.strip()
        if key in ("capacity", "slots"):
            try:
                out["capacity"] = int(float(val))
            except (ValueError, TypeError):
                pass
        elif key in ("no_show_rate", "noshow_rate", "no_show", "noshow"):
            try:
                out["no_show_rate"] = float(val)
            except (ValueError, TypeError):
                pass
    return out
